class Solution {
public:
    int maxConsecutiveAnswers(string answerKey, int k) {
        int res = 0;
        int n = answerKey.size();
        for (char c : {'T', 'F'}) {
            int left = 0, remain = k;
            for (int right = 0; right < n; right++) {
                if (answerKey[right] != c) remain--;
                while (remain < 0) {
                    if (answerKey[left] != c) remain++;
                    left++;
                }
                res = max(res, right - left + 1);
            }
        }
        return res;
    }
};

